import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useSelector, useDispatch } from 'react-redux';
import { fetchRestaurants, fetchCuisines } from '../store/slices/restaurantSlice';
import { addToCart } from '../store/slices/cartSlice';
import SmartRecommendations from '../components/AI/SmartRecommendations';
import UserPreferenceSetup from '../components/AI/UserPreferenceSetup';

const SimpleHome = () => {
  const dispatch = useDispatch();
  const restaurants = useSelector((state) => state.restaurants);
  const cuisines = useSelector((state) => state.cuisines);
  const [featuredRestaurants, setFeaturedRestaurants] = useState([]);
  const [showPreferenceSetup, setShowPreferenceSetup] = useState(false);
  const [hasPreferences, setHasPreferences] = useState(false);

  useEffect(() => {
    dispatch(fetchRestaurants());
    dispatch(fetchCuisines());
  }, []);

  useEffect(() => {
    if (restaurants.length > 0) {
      setFeaturedRestaurants(restaurants.slice(0, 6));
    }
  }, [restaurants]);

  useEffect(() => {
    // Check if user has set preferences
    const savedPreferences = localStorage.getItem('userMealPreferences');
    setHasPreferences(!!savedPreferences);
  }, []);

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Hero Section */}
      <section className="bg-gradient-to-r from-orange-500 to-red-600 text-white py-20">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
          <h1 className="text-4xl md:text-6xl font-bold mb-6">
            Delicious Food from Tamil Nadu
          </h1>
          <p className="text-xl md:text-2xl mb-8">
            Order from the best restaurants in Chennai, Madurai, Coimbatore & more
          </p>
          <Link
            to="/restaurants"
            className="bg-white text-orange-600 px-8 py-4 rounded-lg text-lg font-semibold hover:bg-gray-100 transition-colors inline-block"
          >
            Browse Restaurants
          </Link>
        </div>
      </section>

      {/* Popular Cuisines */}
      <section className="py-16">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <h2 className="text-3xl font-bold text-center mb-12">Popular Cuisines</h2>
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-6">
            {[
              { name: 'South Indian', emoji: '🍛', count: '50+ dishes' },
              { name: 'Chettinad', emoji: '🌶️', count: '30+ dishes' },
              { name: 'Multi Cuisine', emoji: '🍽️', count: '40+ dishes' },
              { name: 'North Indian', emoji: '🍛', count: '25+ dishes' },
              { name: 'Chinese', emoji: '🥢', count: '20+ dishes' },
              { name: 'Beverages', emoji: '☕', count: '15+ drinks' }
            ].map((cuisine) => (
              <Link
                key={cuisine.name}
                to={`/restaurants?cuisine=${cuisine.name}`}
                className="text-center p-6 bg-white rounded-lg shadow-sm hover:shadow-md transition-shadow"
              >
                <div className="text-4xl mb-3">{cuisine.emoji}</div>
                <h3 className="font-semibold text-gray-900">{cuisine.name}</h3>
                <p className="text-sm text-gray-600">{cuisine.count}</p>
              </Link>
            ))}
          </div>
        </div>
      </section>

      {/* Featured Restaurants */}
      <section className="py-16 bg-white">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <h2 className="text-3xl font-bold text-center mb-12">Featured Restaurants</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {featuredRestaurants.map((restaurant) => (
              <Link
                key={restaurant.id}
                to={`/restaurant/${restaurant.id}`}
                className="bg-white rounded-lg shadow-sm hover:shadow-lg transition-shadow overflow-hidden"
              >
                <img
                  src={restaurant.image}
                  alt={restaurant.name}
                  className="w-full h-48 object-cover"
                />
                <div className="p-6">
                  <div className="flex justify-between items-start mb-2">
                    <h3 className="text-xl font-semibold text-gray-900">
                      {restaurant.name}
                    </h3>
                    <div className="flex items-center">
                      <span className="text-yellow-400">⭐</span>
                      <span className="text-sm text-gray-600 ml-1">{restaurant.rating}</span>
                    </div>
                  </div>
                  <p className="text-gray-600 mb-2">{restaurant.cuisine}</p>
                  <p className="text-sm text-gray-500 mb-3">{restaurant.city}, {restaurant.area}</p>
                  <div className="flex justify-between items-center">
                    <span className="text-sm text-gray-600">{restaurant.deliveryTime}</span>
                    <span className="text-sm font-medium text-green-600">₹{restaurant.deliveryFee} delivery</span>
                  </div>
                </div>
              </Link>
            ))}
          </div>

          <div className="text-center mt-12">
            <Link
              to="/restaurants"
              className="bg-orange-500 text-white px-8 py-3 rounded-lg font-semibold hover:bg-orange-600 transition-colors"
            >
              View All Restaurants ({mockRestaurants.length})
            </Link>
          </div>
        </div>
      </section>

      {/* Quick Stats */}
      <section className="py-16 bg-gray-100">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-8 text-center">
            <div>
              <div className="text-3xl font-bold text-orange-600 mb-2">{mockRestaurants.length}+</div>
              <div className="text-gray-600">Restaurants</div>
            </div>
            <div>
              <div className="text-3xl font-bold text-orange-600 mb-2">200+</div>
              <div className="text-gray-600">Dishes</div>
            </div>
            <div>
              <div className="text-3xl font-bold text-orange-600 mb-2">6</div>
              <div className="text-gray-600">Cities</div>
            </div>
            <div>
              <div className="text-3xl font-bold text-orange-600 mb-2">30 min</div>
              <div className="text-gray-600">Avg Delivery</div>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default SimpleHome;
